let catalogVersion = 1;

const products = [
  { id: 1, name: 'Apex Pro Laptop', sku: 'APX-LT-001', category: 'Computers', price: 1299, inventory: 42, status: 'In stock' },
  { id: 2, name: 'Orbit X Phone', sku: 'ORB-PH-014', category: 'Mobile', price: 899, inventory: 18, status: 'In stock' },
  { id: 3, name: 'Canvas 11 Tablet', sku: 'CNV-TB-011', category: 'Tablets', price: 549, inventory: 7, status: 'Low stock' },
  { id: 4, name: 'QuietPods Max', sku: 'QPD-HD-208', category: 'Audio', price: 249, inventory: 0, status: 'Out of stock' },
  { id: 5, name: 'Pulse Smartwatch', sku: 'PLS-WT-032', category: 'Wearables', price: 329, inventory: 26, status: 'In stock' },
  { id: 6, name: 'Apex Pro Monitor', sku: 'APX-MN-027', category: 'Computers', price: 479, inventory: 13, status: 'In stock' }
];

export async function getAllProducts() {
  // Represents the read from the catalog database.
  await new Promise(resolve => setTimeout(resolve, 100));
  return products.map(product => ({ ...product }));
}

export async function syncLatestCatalog() {
  // Represents the longer ERP/PIM import. The action deliberately does not await this.
  await new Promise(resolve => setTimeout(resolve, 900));
  catalogVersion += 1;
  return catalogVersion;
}

import { unstable_cache, revalidateTag } from 'next/cache';
import { syncLatestCatalog, getAllProducts } from '@/lib/db';

const PRODUCTS_TAG = 'products';

const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ['catalog-products'],
  { tags: [PRODUCTS_TAG], revalidate: 60 }
);

export default async function Page() {
  async function syncCatalog() {
    'use server';

    // Invalidate the shared catalog cache as soon as the sync is requested,
    // then let the potentially large import run without blocking this page.
    revalidateTag(PRODUCTS_TAG, 'max');
    void syncLatestCatalog().then(() => revalidateTag(PRODUCTS_TAG, 'max'));
  }

  const products = await getCachedProducts();
  const inStock = products.filter(product => product.inventory > 0).length;
  const lowStock = products.filter(product => product.inventory > 0 && product.inventory < 10).length;

  return (
    <main className="shell">
      <header className="topbar">
        <div className="brand"><span className="brand-mark">N</span><span>Northstar</span></div>
        <div className="topbar-right"><span className="workspace-label">Operations workspace</span><span className="avatar">JD</span></div>
      </header>

      <div className="layout">
        <aside className="sidebar">
          <p className="eyebrow">WORKSPACE</p>
          <nav>
            <a href="#overview">▦ <span>Overview</span></a>
            <a className="active" href="#catalog">▤ <span>Catalog</span><b>6</b></a>
            <a href="#orders">□ <span>Orders</span></a>
            <a href="#customers">♙ <span>Customers</span></a>
          </nav>
          <p className="eyebrow second">MANAGE</p>
          <nav>
            <a href="#integrations">⇄ <span>Integrations</span></a>
            <a href="#settings">⚙ <span>Settings</span></a>
          </nav>
          <div className="help-card"><strong>Need a hand?</strong><span>Visit the help center</span><a href="#help">↗</a></div>
        </aside>

        <section className="content" id="catalog">
          <div className="page-heading">
            <div><p className="breadcrumb">Workspace / Catalog</p><h1>Product catalog</h1><p className="subtitle">Manage your products, pricing, and inventory in one place.</p></div>
            <form action={syncCatalog}><button className="sync-button" type="submit"><span>↻</span> Sync latest catalog</button></form>
          </div>

          <div className="stats">
            <div><span className="stat-icon purple">▤</span><div><p>Total products</p><strong>{products.length}</strong><small>↑ 8.2% <em>vs last month</em></small></div></div>
            <div><span className="stat-icon green">✓</span><div><p>In stock</p><strong>{inStock}</strong><small>↑ 4.6% <em>vs last month</em></small></div></div>
            <div><span className="stat-icon amber">!</span><div><p>Low stock</p><strong>{lowStock}</strong><small className="neutral">Needs attention</small></div></div>
            <div><span className="stat-icon blue">$</span><div><p>Catalog value</p><strong>$48.2k</strong><small>↑ 12.4% <em>vs last month</em></small></div></div>
          </div>

          <div className="catalog-card">
            <div className="card-toolbar"><div><h2>All products <span>{products.length}</span></h2><p>Last synced just now · Changes may take a moment to appear.</p></div><div className="tools"><label className="search">⌕<input placeholder="Search products" /></label><button className="filter">≡ Filter <span>2</span></button><button className="more">•••</button></div></div>
            <div className="table-wrap"><table><thead><tr><th><input type="checkbox" aria-label="Select all products" /></th><th>PRODUCT ↕</th><th>SKU ↕</th><th>CATEGORY ↕</th><th>PRICE ↕</th><th>INVENTORY ↕</th><th>STATUS</th><th></th></tr></thead><tbody>{products.map(product => <tr key={product.id}><td><input type="checkbox" aria-label={`Select ${product.name}`} /></td><td><div className="product"><span className={`product-image image-${product.id}`}>{product.name.slice(0, 1)}</span><strong>{product.name}</strong></div></td><td className="muted">{product.sku}</td><td>{product.category}</td><td>${product.price.toLocaleString()}</td><td>{product.inventory} units</td><td><span className={`pill ${product.status.toLowerCase().replaceAll(' ', '-')}`}>{product.status}</span></td><td><button className="row-more">•••</button></td></tr>)}</tbody></table></div>
            <footer className="pagination"><span>Showing <strong>1–{products.length}</strong> of <strong>{products.length}</strong> products</span><div><button disabled>← Previous</button><button className="current">1</button><button disabled>Next →</button></div></footer>
          </div>
        </section>
      </div>
    </main>
  );
}

